const allowedUserId = 'REPLACE_WITH_TELEGRAM_USER_ID';
const message = $json.message;
if (!message || String(message.from?.id) !== allowedUserId) {
  throw new Error('Unauthorized Telegram sender');
}
const text = [message.text, message.caption].filter(Boolean).join(' ');
const urls = text.match(/https?:\/\/[^\s<>()]+/g) ?? [];
if (urls.length !== 1) {
  throw new Error('Send exactly one http or https opportunity URL');
}
const sourceUrl = new URL(urls[0].replace(/[.,;!?]+$/, ''));
const hostname = sourceUrl.hostname.toLowerCase().replace(/\.$/, '');
const privateIpv4 = /^(127\.|10\.|169\.254\.|192\.168\.|172\.(1[6-9]|2[0-9]|3[01])\.)/;
if (sourceUrl.username || sourceUrl.password || !['http:', 'https:'].includes(sourceUrl.protocol) || !['', '80', '443'].includes(sourceUrl.port) || hostname === 'localhost' || hostname.endsWith('.localhost') || hostname.endsWith('.local') || hostname.endsWith('.internal') || privateIpv4.test(hostname)) {
  throw new Error('Source URL is not a safe public web target');
}
return [{ json: {
  chat_id: message.chat.id,
  telegram_user_id: message.from.id,
  telegram_update_id: $json.update_id,
  source_url: sourceUrl.toString(),
  received_at: new Date().toISOString(),
  status: 'pending'
} }];

